import java.util.*;class Player{static int R,C,px,py,wb,ex;static char[][]G;static int[]dx={1,-1,0,0},dy={0,0,1,-1};static String[]dn={"RIGHT","LEFT","DOWN","UP"};static int tx,ty;static Map<Integer,Integer>bfs(char goal,String avoid){var q=new ArrayDeque<int[]>();var cf=new HashMap<Integer,Integer>();var vis=new HashSet<Integer>();q.add(new int[]{px,py});vis.add(py*C+px);while(!q.isEmpty()){var p=q.poll();int x=p[0],y=p[1];for(int i=0;i<4;i++){int nx=x+dx[i],ny=y+dy[i],k=ny*C+nx;if(nx>=0&&nx<C&&ny>=0&&ny<R&&!vis.contains(k)&&avoid.indexOf(G[ny][nx])<0){vis.add(k);cf.put(k,y*C+x);q.add(new int[]{nx,ny});if(G[ny][nx]==goal){tx=nx;ty=ny;return cf;}}}}tx=ty=-1;return cf;}public static void main(String[]a){var s=new Scanner(System.in);R=s.nextInt();C=s.nextInt();s.nextInt();for(;;){py=s.nextInt();px=s.nextInt();s.nextLine();G=new char[R][];for(int y=0;y<R;y++){G[y]=s.nextLine().toCharArray();for(int x=0;x<C;x++)if(G[y][x]=='C'&&x==px&&y==py)wb=1;}Map<Integer,Integer>cf;if(ex==0){cf=bfs('?',"#C");if(tx<0)ex=1;}if(ex>0){cf=wb>0?bfs('T',"#"):bfs('C',"#");}else cf=bfs('?',"#C");int cx=tx,cy=ty;while(cf.containsKey(cy*C+cx)){int p=cf.get(cy*C+cx),nx2=p%C,ny2=p/C;if(nx2==px&&ny2==py)break;cx=nx2;cy=ny2;}for(int i=0;i<4;i++)if(px+dx[i]==cx&&py+dy[i]==cy){System.out.println(dn[i]);break;}}}}